module RefModule(
	input clk,
	input reset_n,
	output reg enable);reg [2:0] unused_count;

always @(posedge clk or negedge reset_n) begin
	if (!reset_n) begin
		unused_count <= 3'b000;
		enable <= 0;
	end else if (unused_count == 3'b100) begin
		unused_count <= 3'b000;
		enable <= 1;
	end else begin
		unused_count <= unused_count + 1;
		enable <= 0;
	end
end

endmodule
